function parseRange(s) {
    if (typeof s !== 'string') s = String(s);
    var idx = s.indexOf('-');
    if (idx === -1) return [parseInt(s, 10)];
    var a = parseInt(s.substring(0, idx), 10);
    var b = parseInt(s.substring(idx + 1), 10);
    if (isNaN(a) || isNaN(b)) return [parseInt(s, 10)];
    var result = [];
    if (a <= b) {
        for (var i = a; i <= b; i++) result.push(i);
    } else {
        for (var j = a; j >= b; j--) result.push(j);
    }
    return result;
}
